parameters.jsonBody:
={{ JSON.stringify({
  model: 'claude-opus-4-8',
  max_tokens: 2048,
  system: 'You maintain the contact database for District Angels, a DC-area angel investing community. You receive a free-text note about one or more people, written informally by a team member. Extract a structured contact update for EACH person mentioned. Infer tags conservatively - only what the text supports. types values: angel, founder, operator, expert, sponsor, volunteer, embassy, friend. Leave fields empty rather than guessing.',
  output_config: { format: { type: 'json_schema', schema: {
    type: 'object',
    properties: {
      contacts: { type: 'array', items: {
        type: 'object',
        properties: {
          full_name: { type: 'string' },
          email: { type: 'string' },
          linkedin_url: { type: 'string' },
          city: { type: 'string' },
          types: { type: 'array', items: { type: 'string' } },
          sectors: { type: 'array', items: { type: 'string' } },
          stages: { type: 'array', items: { type: 'string' } },
          check_size: { type: 'string' },
          offers: { type: 'array', items: { type: 'string' } },
          notes: { type: 'string' }
        },
        required: ['full_name','email','linkedin_url','city','types','sectors','stages','check_size','offers','notes'],
        additionalProperties: false
      }}
    },
    required: ['contacts'],
    additionalProperties: false
  }}},
  messages: [{ role: 'user', content: $json.text }]
}) }}

parameters.jsCode:
const slack = $('Skip system & bot messages').first().json;
const textBlock = $json.content.find(b => b.type === 'text');
const parsed = JSON.parse(textBlock.text);
return parsed.contacts.map(c => ({ json: {
  slack_ts: slack.ts,
  raw_text: slack.text,
  status: 'pending',
  full_name: c.full_name,
  email: c.email,
  linkedin_url: c.linkedin_url,
  city: c.city,
  types: (c.types || []).join(', '),
  sectors: (c.sectors || []).join(', '),
  stages: (c.stages || []).join(', '),
  check_size: c.check_size,
  offers: (c.offers || []).join(', '),
  notes: c.notes
}}));

